explain plan for
select /*+ INDEX_COMBINE(CCM) */ distinct initcap(br.BR_nm) as "Branch", (select initcap(name) from hris.v_emp_master where emp_cd=bm.CC_EMP_CD) "SIC/ASIC Name",decode (EXCL,'Y','Exclusive','N','Non Exclusive') "Excl/Non Excl BCCD", BM.BCCDNAME as "BCCD Name",BM.BCCDCODE as "BCCD Code",TOWN as "BCCD Town",CPD.PINCODE AS "Pin Code",AREA as "Pin Code Area",CCM.MOBILENUMBER as "Calling Number",cpd.COMPLAINTCODE as "Complaint Number",to_char(cpd.ACTIVEDATE,'DD-Mon-YYYY HH:MI:SS AM') "Complaint Date"   ,(select pending_at from call_status_master where id=cpd.ACTIVESTATUS) as "Pending At"  ,(select Getbccdstatus(cpd.COMPLAINTID,cpd.COMPLAINTCODE)from dual) as "Status"  ,(select GetbccdSubstatus(cpd.COMPLAINTID,cpd.COMPLAINTCODE)from dual) as "Sub Status" ,initcap(CUSTOMERNAME) as "Customer Name" ,CCM.HOMEPHONE as "Home Phone",CCM.MOBILENUMBER  as "Mobile Number",CCM.OFFICEPHONE as "Office Phone",CCM.EMAILADDRESS as "Email Address",dvsn_nm as "BU",itm.DIQ_PG_DESC as "PG Desc",TYPE as "Product Type",itm_nm "Product Name",itm.itm_cd "Item Code",bcal.SERVICETYPEDESCRIPTION as "Call Type",CUSTOMER_TYPE as "Customer Type", decode(SERVICECITY,'1','INCITY','2','OUTCITY') as "Nature of Call",SOURCENAME as "Call Source", SERVICEPLACE as "Repair Location",CPD.PROBLEM as "Problem" ,initcap(ccm.ADDRESSLINE1||' '||ccm.ADDRESSLINE2 ||' '||ccm.ADDRESSLINE3||' ' ||ccm.ADDRESSLINE4 ||' ' ||CCM.city ||' '||  CCM.PINCODE) as "Address"  ,CASE WHEN trunc( cpd.REASSIGNEDDATE )> trunc (cpd.ASSIGNEDDATE) THEN to_char(cpd.REASSIGNEDDATE,'DD-Mon-YYYY HH24:MI:SS') ELSE to_char(cpd.ASSIGNEDDATE,'DD-Mon-YYYY HH24:MI:SS') END AS "Assigned / Re-assigned  Date",(bmp.FIRSTNAME||' '||bmp.LASTNAME||' '||bmp.MIDDLENAME) as "Technician Name",to_char(UPDATEDATE,'DD-Mon-YYYY') AS "Attended Date",trunc(sysdate)-trunc(cpd.ACTIVEDATE) as "Pending For No ofDays",decode(cpd.GURANTEESTATUS,1,'Dealer Stock Set',2,'Yes',3,'Not Known',4,'No') "Warranty Status",CPD.PRODUCTSNO as "Product Sr.No.",to_char(CPD.PURCHASEDATE,'DD-Mon-YYYY') as "Purchase Date" ,(select DEFECT_NAME from PRIMARY_DEFECT_MASTER where PRIMARY_DEFECT_ID=cpd.PRIMARY_DEFECT_ID) AS "Defect",null as "Repair Description ",cpd.TECHNICIANACTIONTAKEN as "Technician Remarks" ,(SELECT max(REALLOCATEDATE) FROM BCCD_WRONGALLOCATEDATE where ID =(SELECT max(id) FROM BCCD_WRONGALLOCATEDATE where COMPLAINTPRODUCTID=cpd.COMPLAINTPRODUCTID )) as "Reallocated Date",TEMPORARYUPDATEREMARK as "Temporary Update Remark" from bccd_complaintproduct_details cpd,bccd_complaintcustomermaster ccm,bccd_complaintmaster cm ,bccdmaster bm ,DIVISION_EBS div,item_ebs itm, SERVICECENTERSERVICETYPEMASTER bcal,BCCD_CUSTOMERTYPE_HDR cust,BCCDMANPOWER bmp ,customer_ebs ce,branch_ebs br,BCCD_WRONGALLOCATEDATE bwrdt where  cpd.activestatus not in('0','8') and  CPD.COMPLAINTID=CM.COMPLAINTMASTERID  and CM.CUSTOMERID=CCM.CUSTOMERID and BM.BCCDcode=cpd.bccdid and bccdcode=PARTY_NUMBER  and div.dvsn_cd_ebs=cpd.BUSINESSUNITID and itm.DIQ_PG_CD=cpd.PG_CD and cpd.ITM_CD=itm.ITM_CD and bmp.MANPOWERID(+)=CPD.ASSIGNEDTECHICIAN  and cpd.COMPLAINTPRODUCTID=bwrdt.COMPLAINTPRODUCTID(+) and cpd.typeofcall=bcal.SERVICETYPEID AND Cust.CUSTOMER_TYPE_ID=CCM.CUSTOMERTYPE and br.br_cd=cpd.br_cd and bccdcode in (  select DISTINCT PARTY_NUMBER from customer_ebs where trrtry_Cd=(select br_cd_ebs from branch_ebs where br_cd =(select brcode from hris.v_emp_master where emp_cd='Z416')) and upper(class_cd_Desc)='CCDEALERS' AND STATUS='A')  and TRUNC(cpd.ACTIVEDATE) between ('27-Nov-2015') and ('27-Dec-2015') order by "BCCD Name","Complaint Date" asc
@?/rdbms/admin/utlxpls;
